import { compileTypeScriptToGnosis, serializeTypeScriptBridgeResult } from './src/ts-bridge';
import fs from 'node:fs';

const source = fs.readFileSync('gnosis-betti-wasm/test_bridge.ts', 'utf8');
const compiled = compileTypeScriptToGnosis(source, {
  exportName: 'hello',
  sourceFilePath: 'test_bridge.ts',
});

const serialized = serializeTypeScriptBridgeResult(compiled);
process.stdout.write(JSON.stringify(serialized, null, 2) + '\n');
